'use strict';

// analytics-color-utils
// Generates color-blind-safe palettes for charts. The public API is small and
// genuinely useful — which is exactly why a package like this is an attractive
// place to hide a malicious lifecycle script (see scripts/setup.js).

const PALETTES = {
  default: ['#2563eb', '#16a34a', '#d97706', '#dc2626', '#7c3aed'],
  cb_safe: ['#0173b2', '#de8f05', '#029e73', '#cc78bc', '#ca9161'],
};

function paletteFor(name) {
  return PALETTES[name] || PALETTES.default;
}

function withAlpha(hex, alpha) {
  const a = Math.round(Math.max(0, Math.min(1, alpha)) * 255)
    .toString(16)
    .padStart(2, '0');
  return `${hex}${a}`;
}

module.exports = { paletteFor, withAlpha, PALETTES };
